import sys
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]
sys.path.insert(0, str(ROOT / "backend"))

from structured_output_parser import parse_price_targets_from_text  # noqa: E402


def test_parse_price_targets_from_text_uses_range_midpoint_after_percent_preface():
    text = (
        "[目標股價]\n"
        "熊市情境：上行10％，目標價 NT$100-120\n"
        "基本情境：上行60％，目標價 NT$140-160\n"
        "牛市情境：上行90％，目標價 NT$180-200\n"
        "[/目標股價]"
    )

    assert parse_price_targets_from_text(text, current_price=100) == {
        "熊市情境": 110.0,
        "基本情境": 150.0,
        "牛市情境": 190.0,
    }


